export function loadState() {
  try {
    const s = localStorage.getItem(STORE_KEY);
    if (s) {
      const saved = JSON.parse(s);
      const base = defaultState();
      // Merge top-level keys from defaultState that are missing in saved data
      // (e.g. refCycles added after initial save)
      for (const key of Object.keys(base)) {
        if (saved[key] === undefined) saved[key] = base[key];
      }
      return saved;
    }
  } catch(e) {
    alert('Les données sauvegardées sont corrompues. L\'application repart sur les données initiales.');
    localStorage.removeItem(STORE_KEY);
    return defaultState();
  }
  return null;
}

export function saveState(state) {
  localStorage.setItem(STORE_KEY, JSON.stringify(state));
}

export function currentCycle(state) {
  return state.cycles.find(c => c.id === state.currentCycleId);
}

