// Injecte les données eau initiales — merge entrée par entrée sans écraser l'existant
export function migrateWater(state) {
  for (const cycle of state.cycles) {
    if (cycle.id !== WATER_INIT.cycleId) continue;
    if (!cycle.water) cycle.water = {};
    for (const [date, entry] of Object.entries(WATER_INIT.entries)) {
      if (!cycle.water[date]) cycle.water[date] = entry;
    }
    // Toujours forcer l'index de référence cycle (corrige les migrations précédentes)
    cycle.indexStart.water_m3 = WATER_INIT.indexStart;
  }
}

// Marque automatiquement comme prélevés tous les paiements dont la date est passée
export function autoMarkPayments(state) {
  const today = new Date().toISOString().slice(0, 10);
  let changed = false;
  for (const cycle of state.cycles) {
    for (const p of (cycle.payments || [])) {
      if (!p.done && p.date <= today) {
        p.done = true;
        changed = true;
      }
    }
  }
  return changed;
}
